// Task "Floor" select values → floor-plan story key (Rooftop has no plan).
export const FLOOR_TO_STORY: Record<string, string> = {
  '1st floor': '1',
  '2nd floor': '2',
  '3rd floor': '3',
  '4th floor': '4',
}

export function storyForFloor(floor: string): string | null {
  return FLOOR_TO_STORY[floor] ?? null
}
